INSERT INTO public.exercises (author_id, title, description, dataset_id, target_col, y_col, condition_col, difficulty, visibility) VALUES
('14ffc992-f935-4f5f-9ea0-03bd9f14b9fc', 'Tips: recover the total bill', 'Easy warm-up. Some total_bill values were dropped completely at random. Impute and see how close your slope of tip ~ total_bill lands to the truth.', '00000000-0000-4000-8000-000000000001', 'total_bill', 'tip', 'size', 'easy', 'public'),
('14ffc992-f935-4f5f-9ea0-03bd9f14b9fc', 'Penguins: bill length under a condition', 'Medium. bill_length_mm goes missing conditional on another body measurement. Constant imputation will bias the slope vs body_mass_g — find a smarter fill.', '00000000-0000-4000-8000-000000000002', 'bill_length_mm', 'body_mass_g', 'flipper_length_mm', 'medium', 'public'),
('14ffc992-f935-4f5f-9ea0-03bd9f14b9fc', 'MPG: missing in the tails', 'Hard. mpg is deleted in the top or bottom quartile, conditional on weight. Naive mean imputation will flatten the regression — try grouped fills.', '00000000-0000-4000-8000-000000000003', 'mpg', 'horsepower', 'weight', 'hard', 'public'),
('14ffc992-f935-4f5f-9ea0-03bd9f14b9fc', 'Car crashes: insurance vs total', 'Medium. total crashes go missing where alcohol involvement is above/below the mean. Recover the slope against ins_premium.', '00000000-0000-4000-8000-000000000005', 'total', 'ins_premium', 'alcohol', 'medium', 'public'),
('14ffc992-f935-4f5f-9ea0-03bd9f14b9fc', 'Health expenditure vs life expectancy', 'Easy. Spending_USD dropped MCAR. Try mean, median, and a Year-grouped fill to chase the true slope.', '00000000-0000-4000-8000-000000000007', 'Spending_USD', 'Life_Expectancy', 'Year', 'easy', 'public');
